public class JavaFileReader {

  /**
   * Logger for debugging purposes
   */
  private static final Logger LOGGER = LogManager.getLogger(JavaFileReader.class.getSimpleName());

  /**
   * Read the Java program and return all classes of the program.
   * 
   * @return List containing all classes of the program
   */
  public List<ProgramElement> readProgram(Path pathToProgram) {
    return readProgram(pathToProgram.toFile());
  }

  /**
   * Read the Java program and return all classes of the program.
   * 
   * @return List containing all classes of the program
   */
  public List<ProgramElement> readProgram(File file) {
    List<ProgramElement> programStructure = new ArrayList<>();
    CompilationUnit compilationUnit = null;
    try {
      compilationUnit = JavaParser.parse(file);
    } catch (ParseException e) {
      LOGGER.error("Could not read program at path {}", file.getAbsolutePath());
      e.printStackTrace();
    }

    List<TypeDeclaration> types = compilationUnit.getTypes();
    for (TypeDeclaration type : types) {
      if (type instanceof ClassOrInterfaceDeclaration) {
        programStructure.add(readClass((ClassOrInterfaceDeclaration) type));
      } else {
        LOGGER.warn("Found type {} but is not of type ClassOrInterfaceDeclaration!", type.getClass().getSimpleName());
      }
    }

    return programStructure;
  }

